1872	
1873	- [ ] **Step 3: Implement — use JSX, never `dangerouslySetInnerHTML`**
1874	
1875	The `value` is a user-scoped address string. We compute dark-module positions (numbers only) via `qrcode-generator` and render them as JSX `<rect>` elements — the string itself only appears in `aria-label`, which React escapes automatically.
1876	
1877	```tsx
1878	// apps/web/src/components/ui/QRCode.tsx
1879	import qrcode from "qrcode-generator";
1880	
1881	export function QRCode({
1882	  value,
1883	  size = 128,
1884	}: {
1885	  value: string;
1886	  size?: number;
1887	}) {
1888	  const qr = qrcode(0, "M");
1889	  qr.addData(value);
1890	  qr.make();
1891	
1892	  const cells = qr.getModuleCount();
1893	  const cellSize = size / cells;
1894	
1895	  const rects: { x: number; y: number }[] = [];
1896	  for (let y = 0; y < cells; y++) {
1897	    for (let x = 0; x < cells; x++) {
1898	      if (qr.isDark(y, x)) rects.push({ x, y });
1899	    }
1900	  }
1901	
1902	  return (
1903	    <svg
1904	      width={size}
1905	      height={size}
1906	      viewBox={`0 0 ${size} ${size}`}
1907	      role="img"
1908	      aria-label={`QR code for ${value}`}
1909	      className="text-[var(--color-text)] bg-white p-1 rounded"
1910	    >
1911	      {rects.map((r) => (
1912	        <rect
1913	          key={`${r.x}-${r.y}`}
1914	          x={r.x * cellSize}
1915	          y={r.y * cellSize}
1916	          width={cellSize}
1917	          height={cellSize}
1918	          fill="currentColor"
1919	        />
1920	      ))}
1921	    </svg>
1922	  );
1923	}
1924	```
