2020	// apps/web/src/components/ui/Table.tsx
2021	import { useState, type ReactNode } from "react";
2022	import { cn } from "@/lib/utils";
2023	
2024	export interface Column<T> {
2025	  key: string;
2026	  header: ReactNode;
2027	  align?: "left" | "right";
2028	  render?: (row: T) => ReactNode;
2029	  sortValue?: (row: T) => number | string;
2030	}
2031	
2032	type SortDir = "asc" | "desc";
2033	
2034	export function Table<T>({
2035	  columns,
2036	  rows,
2037	  rowKey,
2038	  onRowClick,
2039	  className,
2040	}: {
2041	  columns: Column<T>[];
2042	  rows: T[];
2043	  rowKey: (row: T) => string;
2044	  onRowClick?: (row: T) => void;
2045	  className?: string;
2046	}) {
2047	  const [sortKey, setSortKey] = useState<string | null>(null);
2048	  const [sortDir, setSortDir] = useState<SortDir>("asc");
2049	
2050	  const sortable = (col: Column<T>) => col.sortValue != null;
2051	
2052	  const sorted = (() => {
2053	    if (!sortKey) return rows;
2054	    const col = columns.find((c) => c.key === sortKey);
2055	    if (!col?.sortValue) return rows;
2056	    const get = col.sortValue;
2057	    return [...rows].sort((a, b) => {
2058	      const av = get(a);
2059	      const bv = get(b);
2060	      if (av < bv) return sortDir === "asc" ? -1 : 1;
2061	      if (av > bv) return sortDir === "asc" ? 1 : -1;
2062	      return 0;
2063	    });
2064	  })();
2065	
2066	  const toggleSort = (key: string) => {
2067	    if (sortKey === key) {
2068	      setSortDir((d) => (d === "asc" ? "desc" : "asc"));
2069	    } else {
2070	      setSortKey(key);
2071	      setSortDir("asc");
2072	    }
2073	  };
2074	
2075	  return (
2076	    <table className={cn("w-full text-sm border-collapse", className)}>
2077	      <thead>
2078	        <tr>
2079	          {columns.map((c) => (
2080	            <th
2081	              key={c.key}
2082	              scope="col"
2083	              aria-sort={
2084	                sortKey === c.key
2085	                  ? sortDir === "asc"
2086	                    ? "ascending"
2087	                    : "descending"
2088	                  : undefined
2089	              }
2090	              onClick={sortable(c) ? () => toggleSort(c.key) : undefined}
2091	              className={cn(
2092	                "text-[10px] uppercase tracking-[0.08em] font-normal " +
2093	                  "text-[var(--color-text-faint)] border-b border-[var(--color-border)] " +
2094	                  "py-2 px-2",
2095	                c.align === "right" ? "text-right" : "text-left",
2096	                sortable(c) &&
2097	                  "cursor-pointer select-none hover:text-[var(--color-text)]",
2098	              )}
2099	            >
2100	              {c.header}
2101	            </th>
2102	          ))}
2103	        </tr>
2104	      </thead>
2105	      <tbody>
2106	        {sorted.map((r) => (
2107	          <tr
2108	            key={rowKey(r)}
2109	            onClick={onRowClick ? () => onRowClick(r) : undefined}
2110	            className={cn(
2111	              "border-b border-[var(--color-border)]",
2112	              onRowClick && "cursor-pointer hover:bg-[var(--color-surface)]",
2113	            )}
2114	          >
2115	            {columns.map((c) => (
2116	              <td
2117	                key={c.key}
2118	                className={cn(
2119	                  "py-2 px-2 tabular-nums",
2120	                  c.align === "right" ? "text-right" : "text-left",
2121	                )}
2122	              >
2123	                {c.render
2124	                  ? c.render(r)
2125	                  : ((r as Record<string, unknown>)[c.key] as ReactNode)}
2126	              </td>
2127	            ))}
2128	          </tr>
2129	        ))}
2130	      </tbody>
2131	    </table>
2132	  );
2133	}
